SELECT shift_type, SUM(shift_duration) AS total_duration, AVG(break_time) AS avg_break_time
FROM shifts
GROUP BY shift_type;

SELECT COUNT(*) AS swap_count
FROM shift_swaps
WHERE swap_status = 'declined';

SELECT swap_status, COUNT(*) AS swap_count
FROM shift_swaps
GROUP BY swap_status;

SELECT COUNT(*) 
FROM employees 
WHERE employee_id NOT IN (SELECT DISTINCT employee_id FROM schedules);

SELECT swap_id, employee_id_from, employee_id_to, swap_status
FROM shift_swaps
WHERE swap_status = 'pending';

SELECT request_status
FROM overtime_requests
WHERE employee_id = 0;

SELECT shift_type
FROM shifts
WHERE shift_id = 0;

SELECT employees.first_name || ' ' || employees.last_name AS full_name
FROM employees
WHERE employees.employee_id IN (
  SELECT overtime_requests.employee_id
  FROM overtime_requests
);

SELECT DISTINCT e.employee_id
FROM employees e
JOIN schedules s ON e.employee_id = s.employee_id;

SELECT request_type, COUNT(*) AS request_count
FROM time_off_requests
GROUP BY request_type;

SELECT shift_type, AVG(shift_duration) AS average_shift_duration
FROM shifts
GROUP BY shift_type;

SELECT employee_id, request_type
FROM time_off_requests
WHERE request_status = 'approved';
